import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell,
} from "recharts";

interface ExerciseAnalyticDay {
  date: string;
  totalVolume: number;
  maxWeight: number;
  totalSets: number;
  totalReps: number;
  totalDistance: number;
}

function formatDate(d: string): string {
  const date = new Date(d + "T00:00:00");
  return date.toLocaleDateString("en-US", { month: "short", day: "numeric" });
}

// Convert Tailwind classes like "bg-primary/60" to hex colors for Recharts
// Fallback to basic colors if specific classes aren't matched
const getFillColor = (colorStr: string) => {
  if (colorStr.includes("primary")) return "#ea580c"; // Matches our orange primary
  if (colorStr.includes("purple")) return "#a855f7";
  if (colorStr.includes("blue")) return "#3b82f6";
  if (colorStr.includes("green")) return "#22c55e";
  return "#64748b"; // muted fallback
};

const CustomTooltip = ({ active, payload, chartLabel }: any) => {
  if (!active || !payload?.length) return null;

  return (
    <div className="bg-popover text-popover-foreground border px-3 py-2 rounded shadow-md text-sm">
      <p className="font-semibold mb-1">
        {formatDate(payload[0]?.payload?.date)}
      </p>
      <p>
        <span className="text-muted-foreground mr-2">{chartLabel}:</span>
        <span className="font-medium">{payload[0]?.value}</span>
      </p>
    </div>
  );
};

export function MiniBarChart({
  data,
  valueKey,
  color,
  label,
}: Readonly<{
  data: ExerciseAnalyticDay[];
  valueKey: keyof ExerciseAnalyticDay;
  color: string;
  label: string;
}>) {
  if (data.length === 0) return null;

  const fillColor = getFillColor(color);

  return (
    <div className="space-y-3 p-4 border rounded-lg bg-card text-card-foreground shadow-sm">
      <div className="flex justify-between items-center">
        <p className="text-sm font-semibold">{label}</p>
      </div>
      <div className="h-[200px] w-full" data-testid={`chart-${valueKey}`}>
        <ResponsiveContainer width="100%" height="100%">
          <BarChart
            data={data}
            margin={{ top: 5, right: 5, left: -20, bottom: 5 }}
          >
            <CartesianGrid
              strokeDasharray="3 3"
              vertical={false}
              stroke="hsl(var(--border))"
            />
            <XAxis
              dataKey="date"
              tickFormatter={formatDate}
              fontSize={12}
              tickLine={false}
              axisLine={false}
              tick={{ fill: "hsl(var(--muted-foreground))" }}
            />
            <YAxis
              fontSize={12}
              tickLine={false}
              axisLine={false}
              tick={{ fill: "hsl(var(--muted-foreground))" }}
            />
            <Tooltip
              cursor={{ fill: "hsl(var(--muted)/0.5)" }}
              content={<CustomTooltip chartLabel={label} />}
            />
            <Bar
              dataKey={valueKey as string}
              radius={[4, 4, 0, 0]}
              maxBarSize={40}
            >
              {data.map((entry) => (
                <Cell
                  key={`cell-${entry.date}`}
                  fill={fillColor}
                  fillOpacity={0.8}
                />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

export type { ExerciseAnalyticDay };

import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { SuggestionCard, type Suggestion } from "./SuggestionCard";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { getCurrentTimeString } from "@/lib/dateUtils";
import type { Message } from "@/hooks/useChatSession";
import type { TimelineEntry } from "@shared/schema";

interface UseSuggestionsOptions {
  timeline: TimelineEntry[];
  addLocalMessage: (message: Message) => void;
  saveMessage: (msg: { role: string; content: string }) => void;
}

export function useSuggestions({ timeline, addLocalMessage, saveMessage }: UseSuggestionsOptions) {
  const [pendingSuggestions, setPendingSuggestions] = useState<Suggestion[]>([]);
  const [applyingId, setApplyingId] = useState<string | null>(null);

  const suggestionsMutation = useMutation({
    mutationFn: async () => {
      const res = await apiRequest("POST", "/api/v1/timeline/ai-suggestions", {});
      return res.json();
    },
    onSuccess: (data: { suggestions: Suggestion[] }) => {
      let responseContent: string;
      if (!data.suggestions || data.suggestions.length === 0) {
        responseContent = "Your upcoming workouts look well-balanced! I don't have any specific improvements to suggest right now.";
        setPendingSuggestions([]);
      } else {
        responseContent = `I have ${data.suggestions.length} suggestion${data.suggestions.length > 1 ? 's' : ''} for your upcoming workouts. Review them below and click Apply to add them to your plan.`;
        setPendingSuggestions(data.suggestions);
      }

      const suggestionsMessage: Message = {
        id: Date.now().toString(),
        role: "assistant",
        content: responseContent,
        timestamp: getCurrentTimeString(),
      };
      addLocalMessage(suggestionsMessage);
      saveMessage({ role: "assistant", content: responseContent });
    },
    onError: (error: any) => {
      let errorContent = "Sorry, I couldn't analyze your workouts right now. Please try again.";
      if (error?.message?.includes("429") || error?.status === 429) {
        errorContent = "You're sending requests too quickly. Please wait a moment and try again.";
      } else if (error?.message?.includes("network") || error?.message?.includes("fetch")) {
        errorContent = "Network error — please check your connection and try again.";
      }
      const errorMessage: Message = {
        id: Date.now().toString(),
        role: "assistant",
        content: errorContent,
        timestamp: getCurrentTimeString(),
      };
      addLocalMessage(errorMessage);
    },
  });

  const handleApplySuggestion = async (suggestion: Suggestion) => {
    setApplyingId(suggestion.workoutId);
    try {
      const workoutEntry = timeline.find(e => e.planDayId === suggestion.workoutId);
      if (!workoutEntry) {
        const errorMessage: Message = {
          id: Date.now().toString(),
          role: "assistant",
          content: `Could not find the workout for ${suggestion.focus} (${suggestion.date}). The suggestion is still available to retry.`,
          timestamp: getCurrentTimeString(),
        };
        addLocalMessage(errorMessage);
        return;
      }

      const currentValue = (workoutEntry[suggestion.targetField] as string) || "";
      let newValue: string;

      if (suggestion.action === "append") {
        if (currentValue.trim()) {
          newValue = `${currentValue}\n\nAI suggestion: ${suggestion.recommendation}`;
        } else {
          newValue = `AI suggestion: ${suggestion.recommendation}`;
        }
      } else {
        newValue = suggestion.recommendation;
      }

      await apiRequest("PATCH", `/api/v1/plans/days/${suggestion.workoutId}`, {
        [suggestion.targetField]: newValue,
      });

      queryClient.invalidateQueries({ queryKey: ["/api/v1/timeline"] });
      if (suggestion.action === "replace" && suggestion.targetField === "mainWorkout") {
        queryClient.invalidateQueries({ queryKey: ["/api/v1/exercise-analytics"] });
        queryClient.invalidateQueries({ queryKey: ["/api/v1/personal-records"] });
      }
      setPendingSuggestions(prev => prev.filter(s => s.workoutId !== suggestion.workoutId));

      const confirmMessage: Message = {
        id: Date.now().toString(),
        role: "assistant",
        content: `Applied suggestion to ${suggestion.focus} (${suggestion.date}). The ${suggestion.targetField === "mainWorkout" ? "main workout" : suggestion.targetField} has been updated.`,
        timestamp: getCurrentTimeString(),
      };
      addLocalMessage(confirmMessage);
    } catch {
      const errorMessage: Message = {
        id: Date.now().toString(),
        role: "assistant",
        content: `Failed to apply suggestion to ${suggestion.focus}. Please try again.`,
        timestamp: getCurrentTimeString(),
      };
      addLocalMessage(errorMessage);
    } finally {
      setApplyingId(null);
    }
  };

  const handleDismissSuggestion = (workoutId: string) => {
    setPendingSuggestions(prev => prev.filter(s => s.workoutId !== workoutId));
  };

  const clearSuggestions = () => {
    setPendingSuggestions([]);
  };

  return {
    pendingSuggestions,
    applyingId,
    suggestionsMutation,
    handleApplySuggestion,
    handleDismissSuggestion,
    clearSuggestions,
  };
}

interface SuggestionsListProps {
  readonly suggestions: Suggestion[];
  readonly applyingId: string | null;
  readonly onApply: (suggestion: Suggestion) => void;
  readonly onDismiss: (workoutId: string) => void;
}

export function SuggestionsList({ suggestions, applyingId, onApply, onDismiss }: Readonly<SuggestionsListProps>) {
  if (suggestions.length === 0) return null;

  return (
    <div className="space-y-2">
      {suggestions.map((suggestion) => (
        <SuggestionCard
          key={suggestion.workoutId}
          suggestion={suggestion}
          onApply={() => onApply(suggestion)}
          onDismiss={() => onDismiss(suggestion.workoutId)}
          isApplying={applyingId === suggestion.workoutId}
        />
      ))}
    </div>
  );
}

import { useState, useRef } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { BookOpen, Plus, Upload, Trash2, Loader2, FileText } from "lucide-react";
import {
  useCoachingMaterials,
  useCreateCoachingMaterial,
  useDeleteCoachingMaterial,
} from "@/hooks/useCoachingMaterials";
import { useToast } from "@/hooks/use-toast";
import * as pdfjsLib from "pdfjs-dist";
import pdfjsWorker from "pdfjs-dist/build/pdf.worker.min.mjs?url";
import mammoth from "mammoth";

pdfjsLib.GlobalWorkerOptions.workerSrc = pdfjsWorker;

/** Strip null bytes and non-printable control characters that PostgreSQL text columns reject. */
function sanitizeText(text: string): string {
  return text.replaceAll(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, "");
}

async function extractPdfText(file: File): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const pages: string[] = [];
  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const textContent = await page.getTextContent();
    pages.push(textContent.items.map((item) => ("str" in item ? item.str : "")).join(" "));
  }
  return sanitizeText(pages.join("\n\n"));
}

async function extractDocxText(file: File): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const result = await mammoth.extractRawText({ arrayBuffer });
  return sanitizeText(result.value);
}

async function extractFileText(file: File): Promise<string> {
  const ext = file.name.split(".").pop()?.toLowerCase();
  if (ext === "pdf") return extractPdfText(file);
  if (ext === "docx") return extractDocxText(file);
  return sanitizeText(await file.text());
}

function getFileSizeLimit(file: File): number {
  return 100000;
}

export function CoachingSection() {
  const { toast } = useToast();
  const { data: materials, isLoading } = useCoachingMaterials();
  const createMutation = useCreateCoachingMaterial();
  const deleteMutation = useDeleteCoachingMaterial();

  const [dialogOpen, setDialogOpen] = useState(false);
  const [dialogType, setDialogType] = useState<"principles" | "document">("principles");
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  const openPrinciplesDialog = () => {
    setDialogType("principles");
    setTitle("");
    setContent("");
    setDialogOpen(true);
  };

  const processSingleFile = async (file: File) => {
    const sizeLimit = getFileSizeLimit(file);
    if (file.size > sizeLimit) {
      toast({ title: "File too large", description: `Maximum file size is 100KB.`, variant: "destructive" });
      return;
    }
    try {
      const text = await extractFileText(file);
      setDialogType("document");
      setTitle(file.name.replace(/\.[^/.]+$/, ""));
      setContent(text.slice(0, 10000));
      setDialogOpen(true);
    } catch {
      toast({ title: "Failed to read file", variant: "destructive" });
    }
  };

  const processBatchFiles = async (files: File[]) => {
    const tooLarge: string[] = [];
    const failed: string[] = [];
    let uploaded = 0;

    for (const file of files) {
      if (file.size > getFileSizeLimit(file)) {
        tooLarge.push(file.name);
        continue;
      }
      try {
        const text = await extractFileText(file);
        await createMutation.mutateAsync({
          title: file.name.replace(/\.[^/.]+$/, ""),
          content: text.slice(0, 10000),
          type: "document",
        });
        uploaded++;
      } catch {
        failed.push(file.name);
      }
    }

    if (uploaded > 0) {
      toast({ title: `Uploaded ${uploaded} document${uploaded > 1 ? "s" : ""}` });
    }
    if (tooLarge.length > 0) {
      toast({
        title: "Files too large",
        description: `Skipped (>500KB): ${tooLarge.join(", ")}`,
        variant: "destructive",
      });
    }
    if (failed.length > 0) {
      toast({
        title: "Upload failed",
        description: `Failed to read: ${failed.join(", ")}`,
        variant: "destructive",
      });
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (files.length === 1) {
      await processSingleFile(files[0]);
    } else {
      await processBatchFiles(Array.from(files));
    }

    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  const handleSave = () => {
    if (!title.trim() || !content.trim()) return;
    createMutation.mutate(
      { title: title.trim(), content: content.trim(), type: dialogType },
      { onSuccess: () => setDialogOpen(false) },
    );
  };

  const handleDelete = (id: string) => {
    deleteMutation.mutate(id);
  };

  return (
    <>
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <BookOpen className="h-5 w-5" />
            Coaching Knowledge
          </CardTitle>
          <CardDescription>
            Add training principles or reference materials for the AI coach to use when making workout decisions
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {isLoading ? (
            <div className="flex items-center justify-center py-4">
              <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
            </div>
          ) : (
            <>
              {materials && materials.length > 0 ? (
                <div className="space-y-2">
                  {materials.map((material) => (
                    <div
                      key={material.id}
                      className="flex items-center justify-between p-3 rounded-lg border bg-card"
                    >
                      <div className="flex items-center gap-3 min-w-0">
                        <FileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <div className="min-w-0">
                          <p className="text-sm font-medium truncate">{material.title}</p>
                          <p className="text-xs text-muted-foreground">
                            {material.type === "principles" ? "Principles" : "Document"} &middot; {Math.round(material.content.length / 1000)}k chars
                          </p>
                        </div>
                      </div>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleDelete(material.id)}
                        disabled={deleteMutation.isPending}
                      >
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-sm text-muted-foreground">
                  No coaching materials added yet. Add training principles or upload reference documents to help the AI coach make better decisions.
                </p>
              )}

              <div className="flex flex-wrap gap-2">
                <Button variant="outline" size="sm" onClick={openPrinciplesDialog}>
                  <Plus className="h-4 w-4 mr-1" />
                  Add Principles
                </Button>
                <Button variant="outline" size="sm" onClick={() => fileInputRef.current?.click()}>
                  <Upload className="h-4 w-4 mr-1" />
                  Upload Document
                </Button>
                <input
                  ref={fileInputRef}
                  type="file"
                  accept=".txt,.md,.csv,.pdf,.docx"
                  multiple
                  className="hidden"
                  onChange={handleFileUpload}
                />
              </div>
            </>
          )}
        </CardContent>
      </Card>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>
              {dialogType === "principles" ? "Add Training Principles" : "Upload Document"}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="material-title">Title</Label>
              <Input
                id="material-title"
                value={title}
                onChange={(e) => setTitle(e.target.value.slice(0, 255))}
                placeholder="e.g., Periodization Guidelines"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="material-content">
                {dialogType === "principles" ? "Training Principles" : "Document Content"}
              </Label>
              <Textarea
                id="material-content"
                value={content}
                onChange={(e) => setContent(e.target.value.slice(0, 50000))}
                placeholder={
                  dialogType === "principles"
                    ? "Paste your training principles, programming rules, or key excerpts here..."
                    : "Document content will appear here after upload..."
                }
                className="min-h-[200px]"
                rows={10}
              />
              <p className="text-xs text-muted-foreground text-right">
                {content.length.toLocaleString()}/50,000
              </p>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleSave}
              disabled={!title.trim() || !content.trim() || createMutation.isPending}
            >
              {createMutation.isPending ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  Saving...
                </>
              ) : (
                "Save"
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Loader2, Download, FileSpreadsheet, FileJson, Sparkles } from "lucide-react";
import { useMutation } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";

export function DataToolsSection() {
  const { toast } = useToast();
  const [unstructuredCount, setUnstructuredCount] = useState<number | null>(null);
  const [parseResults, setParseResults] = useState<{ success: number; failed: number } | null>(null);

  const findUnstructuredMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("GET", "/api/v1/workouts/unstructured");
      return response.json();
    },
    onSuccess: (data: any[]) => {
      setUnstructuredCount(data.length);
      toast({
        title: "Search Complete",
        description: `Found ${data.length} workouts without structured exercise data.`,
      });
    },
    onError: () => {
      toast({
        title: "Search Failed",
        description: "Failed to find unstructured workouts.",
        variant: "destructive",
      });
    },
  });

  const batchReparseMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/v1/workouts/batch-reparse");
      return response.json();
    },
    onSuccess: (data: { total: number; parsed: number; failed: number }) => {
      setParseResults({ success: data.parsed, failed: data.failed });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/timeline"] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/workouts"] });
      toast({
        title: "Parsing Complete",
        description: `Parsed ${data.parsed} workouts successfully. ${data.failed} could not be parsed.`,
      });
    },
    onError: () => {
      toast({
        title: "Parsing Failed",
        description: "Failed to parse workouts with AI.",
        variant: "destructive",
      });
    },
  });

  return (
    <>
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Sparkles className="h-5 w-5" />
            Structure Old Workouts
          </CardTitle>
          <CardDescription>Use AI to convert free-text workout descriptions into structured exercise data</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {unstructuredCount === null && parseResults === null ? (
            <div>
              <p className="text-sm text-muted-foreground mb-4">
                Find and parse unstructured workout descriptions to extract exercise data using AI.
              </p>
              <Button
                onClick={() => findUnstructuredMutation.mutate()}
                disabled={findUnstructuredMutation.isPending}
                data-testid="button-find-unstructured"
                variant="outline"
              >
                {findUnstructuredMutation.isPending ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin mr-2" />
                    Searching...
                  </>
                ) : (
                  "Find Unstructured Workouts"
                )}
              </Button>
            </div>
          ) : null}

          {unstructuredCount !== null && !parseResults ? (
            <div>
              <p className="text-sm text-muted-foreground mb-4" data-testid="text-unstructured-count">
                Found {unstructuredCount} workouts without structured exercise data
              </p>
              {unstructuredCount > 0 ? (
                <Button
                  onClick={() => batchReparseMutation.mutate()}
                  disabled={batchReparseMutation.isPending}
                  data-testid="button-batch-reparse"
                >
                  {batchReparseMutation.isPending ? (
                    <>
                      <Loader2 className="h-4 w-4 animate-spin mr-2" />
                      Parsing...
                    </>
                  ) : (
                    "Parse All with AI"
                  )}
                </Button>
              ) : (
                <p className="text-sm text-muted-foreground">
                  All your workouts are already structured.
                </p>
              )}
            </div>
          ) : null}

          {parseResults ? (
            <div>
              <p className="text-sm text-muted-foreground mb-4" data-testid="text-parse-results">
                Parsed {parseResults.success} workouts successfully. {parseResults.failed} could not be parsed.
              </p>
              <Button
                onClick={() => {
                  setUnstructuredCount(null);
                  setParseResults(null);
                }}
                variant="outline"
                size="sm"
              >
                Run Again
              </Button>
            </div>
          ) : null}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Download className="h-5 w-5" />
            Export Data
          </CardTitle>
          <CardDescription>Download your training data for backup or analysis</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex flex-wrap items-center gap-3">
            <Button
              variant="outline"
              onClick={() => {
                globalThis.location.href = "/api/v1/export?format=csv";
              }}
              data-testid="button-export-csv"
            >
              <FileSpreadsheet className="h-4 w-4 mr-2" />
              Export as CSV
            </Button>
            <Button
