import { useState, useEffect, useCallback } from "react";
import { queryClient } from "@/lib/queryClient";

export function useOnboarding(
  isNewUser: boolean,
  fileInputRef: React.RefObject<HTMLInputElement>,
) {
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [onboardingTriggered, setOnboardingTriggered] = useState(false);
  const [coachOpen, setCoachOpen] = useState(false);
  const [hasAutoOpenedCoach, setHasAutoOpenedCoach] = useState(false);

  useEffect(() => {
    if (isNewUser && !onboardingTriggered && !localStorage.getItem("hyrox-onboarding-complete")) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setOnboardingTriggered(true);
      setShowOnboarding(true);
    }
  }, [isNewUser, onboardingTriggered]);

  useEffect(() => {
    if (!showOnboarding && onboardingTriggered && !hasAutoOpenedCoach) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setHasAutoOpenedCoach(true);
      setTimeout(() => {
        const isCurrentlyMobile = globalThis.innerWidth < 768;
        if (!isCurrentlyMobile) {
          setCoachOpen(true);
        }
      }, 500);
    }
  }, [showOnboarding, onboardingTriggered, hasAutoOpenedCoach]);

  const handleOnboardingComplete = useCallback((choice: "sample" | "import" | "skip") => {
    setShowOnboarding(false);
    if (choice === "import" && fileInputRef.current) {
      setTimeout(() => {
        fileInputRef.current?.click();
      }, 100);
    } else if (choice === "sample") {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/timeline"] });
    }
  }, [fileInputRef]);

  return {
    showOnboarding,
    coachOpen,
    setCoachOpen,
    handleOnboardingComplete,
  };
}

import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { format, addDays } from "date-fns";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

type Step = "welcome" | "units" | "goal" | "plan" | "schedule";

const STEPS: Step[] = ["welcome", "units", "goal", "plan", "schedule"];
const PREV: Partial<Record<Step, Step>> = {
  units: "welcome",
  goal: "units",
  plan: "goal",
  schedule: "plan",
};

const markComplete = () =>
  localStorage.setItem("hyrox-onboarding-complete", "true");

export function useOnboardingWizard(onComplete: (choice: "sample" | "import" | "skip") => void) {
  const { toast } = useToast();
  const [step, setStep] = useState<Step>("welcome");
  const [weightUnit, setWeightUnit] = useState<"kg" | "lbs">("kg");
  const [distanceUnit, setDistanceUnit] = useState<"km" | "miles">("km");
  const [selectedGoal, setSelectedGoal] = useState("first");
  const [createdPlanId, setCreatedPlanId] = useState<string | null>(null);
  const [startDate, setStartDate] = useState<Date>(addDays(new Date(), 1));

  const prefsMutation = useMutation({
    mutationFn: async (prefs: { weightUnit: string; distanceUnit: string }) =>
      (await apiRequest("PATCH", "/api/v1/preferences", prefs)).json(),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/preferences"] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/auth/user"] });
    },
  });

  const sampleMutation = useMutation({
    mutationFn: async () =>
      (await apiRequest("POST", "/api/v1/plans/sample", {})).json(),
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      setCreatedPlanId(data.id);
      setStep("schedule");
    },
    onError: () =>
      toast({ title: "Failed to create plan", variant: "destructive" }),
  });

  const scheduleMutation = useMutation({
    mutationFn: async ({ planId, date }: { planId: string; date: string }) =>
      (
        await apiRequest("POST", `/api/v1/plans/${planId}/schedule`, {
          startDate: date,
        })
      ).json(),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/timeline"] });
      toast({
        title: "Your training plan is ready!",
        description: "Workouts have been scheduled on your timeline.",
      });
      markComplete();
      onComplete("sample");
    },
    onError: () =>
      toast({ title: "Failed to schedule plan", variant: "destructive" }),
  });

  const handleNext = async () => {
    if (step === "welcome") {
      setStep("units");
      return;
    }
    if (step === "units") {
      try {
        await prefsMutation.mutateAsync({ weightUnit, distanceUnit });
      } catch {
        toast({
          title: "Could not save preferences",
          description: "You can update them later in settings.",
          variant: "destructive",
        });
      }
      setStep("goal");
      return;
    }
    if (step === "goal") setStep("plan");
  };

  const handleSkip = () => {
    markComplete();
    onComplete("skip");
  };

  const handleImportPlan = () => {
    markComplete();
    onComplete("import");
  };

  const handleBack = () => {
    if (PREV[step]) {
      setStep(PREV[step]);
    }
  };

  const handleStartTraining = () => {
    if (createdPlanId) {
      scheduleMutation.mutate({
        planId: createdPlanId,
        date: format(startDate, "yyyy-MM-dd"),
      });
    }
  };

  const handleUseSamplePlan = () => {
    sampleMutation.mutate();
  };

  const idx = STEPS.indexOf(step);
  const total = step === "schedule" ? 5 : 4;

  return {
    step,
    idx,
    total,
    weightUnit,
    setWeightUnit,
    distanceUnit,
    setDistanceUnit,
    selectedGoal,
    setSelectedGoal,
    startDate,
    setStartDate,
    handleNext,
    handleSkip,
    handleImportPlan,
    handleBack,
    handleStartTraining,
    handleUseSamplePlan,
    isPrefsPending: prefsMutation.isPending,
    isSamplePending: sampleMutation.isPending,
    isSchedulePending: scheduleMutation.isPending,
  };
}

import { useState, useRef, useCallback } from "react";
import { useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { format, startOfWeek } from "date-fns";
import type { CsvPreviewData } from "@/components/timeline";

interface UsePlanImportOptions {
  onPlanScheduled?: (planId: string) => void;
}

export function usePlanImport({ onPlanScheduled }: UsePlanImportOptions = {}) {
  const { toast } = useToast();
  const [csvPreview, setCsvPreview] = useState<CsvPreviewData | null>(null);
  const [schedulingPlanId, setSchedulingPlanId] = useState<string | null>(null);
  const [startDate, setStartDate] = useState<string>(
    format(startOfWeek(new Date(), { weekStartsOn: 1 }), "yyyy-MM-dd")
  );
  const fileInputRef = useRef<HTMLInputElement>(null);

  const importMutation = useMutation({
    mutationFn: async (data: { csvContent: string; fileName: string }) => {
      const response = await apiRequest("POST", "/api/v1/plans/import", data);
      return response.json();
    },
    onSuccess: (plan) => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      setSchedulingPlanId(plan.id);
      toast({ title: "Plan imported! Now set a start date." });
    },
    onError: () => {
      toast({ title: "Failed to import plan", variant: "destructive" });
    },
  });

  const samplePlanMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/v1/plans/sample", {});
      return response.json();
    },
    onSuccess: (plan) => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      setSchedulingPlanId(plan.id);
      toast({ title: "Sample plan created! Now set a start date." });
    },
    onError: () => {
      toast({ title: "Failed to create sample plan", variant: "destructive" });
    },
  });

  const renamePlanMutation = useMutation({
    mutationFn: async ({ planId, name }: { planId: string; name: string }) => {
      await apiRequest("PATCH", `/api/v1/plans/${planId}`, { name });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/timeline"] });
      toast({ title: "Plan renamed" });
    },
    onError: () => {
      toast({ title: "Failed to rename plan", variant: "destructive" });
    },
  });

  const updatePlanGoalMutation = useMutation({
    mutationFn: async ({ planId, goal }: { planId: string; goal: string | null }) => {
      const response = await apiRequest("PATCH", `/api/v1/plans/${planId}/goal`, { goal });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      toast({ title: "Goal saved" });
    },
    onError: () => {
      toast({ title: "Failed to save goal", variant: "destructive" });
    },
  });

  const schedulePlanMutation = useMutation({
    mutationFn: async ({ planId, startDate: sd }: { planId: string; startDate: string }) => {
      await apiRequest("POST", `/api/v1/plans/${planId}/schedule`, { startDate: sd });
    },
    onSuccess: () => {
      const planIdToSelect = schedulingPlanId;
      queryClient.invalidateQueries({ queryKey: ["/api/v1/timeline", planIdToSelect] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/plans"] });
      if (planIdToSelect) {
        onPlanScheduled?.(planIdToSelect);
      }
      setSchedulingPlanId(null);
      toast({ title: "Training plan scheduled!" });
    },
    onError: () => {
      toast({ title: "Failed to schedule plan", variant: "destructive" });
    },
  });

  const parseCSVForPreview = useCallback((csvContent: string) => {
    const lines = csvContent.trim().split('\n');
    if (lines.length < 2) return [];

    const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replaceAll(/['"]/g, ""));
    const weekIdx = headers.findIndex(h => h.includes('week'));
    const dayIdx = headers.findIndex(h => h.includes('day'));
    const focusIdx = headers.findIndex(h => h.includes('focus') || h.includes('type'));
    const workoutIdx = headers.findIndex(h => h.includes('workout') || h.includes('main'));

    const rows: Array<{ weekNumber: number; dayName: string; focus: string; mainWorkout: string }> = [];

    for (let i = 1; i < Math.min(lines.length, 11); i++) {
      const cols = lines[i].split(',').map(c => c.trim().replaceAll(/['"]/g, ""));
      if (cols.length >= 4) {
        rows.push({
          weekNumber: Number.parseInt(cols[weekIdx] || '1', 10) || 1,
          dayName: cols[dayIdx] || '',
          focus: cols[focusIdx] || '',
          mainWorkout: cols[workoutIdx] || '',
        });
      }
    }
    return rows;
  }, []);

  const handleFileUpload = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.name.endsWith(".csv")) {
      toast({ title: "Please upload a CSV file", variant: "destructive" });
      return;
    }

    file.text().then((csvContent) => {
      const previewRows = parseCSVForPreview(csvContent);
      setCsvPreview({
        fileName: file.name,
        content: csvContent,
        rows: previewRows,
      });
      event.target.value = "";
    }).catch(() => {
      toast({ title: "Failed to read file", variant: "destructive" });
    });
  }, [parseCSVForPreview, toast]);

  const confirmImport = useCallback(() => {
    if (!csvPreview) return;
    importMutation.mutate({ csvContent: csvPreview.content, fileName: csvPreview.fileName });
    setCsvPreview(null);
  }, [csvPreview, importMutation]);

  return {
    csvPreview,
    setCsvPreview,
    schedulingPlanId,
    setSchedulingPlanId,
    startDate,
    setStartDate,
    fileInputRef,
    handleFileUpload,
    confirmImport,
    importMutation,
    samplePlanMutation,
    renamePlanMutation,
    schedulePlanMutation,
    updatePlanGoalMutation,
  };
}

import { useMutation } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";

export function useStravaMutations() {
  const { toast } = useToast();

  const connectStravaMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("GET", "/api/v1/strava/auth");
      return response.json();
    },
    onSuccess: (data: { authUrl: string }) => {
      globalThis.location.href = data.authUrl;
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to initiate Strava connection.",
        variant: "destructive",
      });
    },
  });

  const disconnectStravaMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("DELETE", "/api/v1/strava/disconnect");
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/strava/status"] });
      toast({
        title: "Strava Disconnected",
        description: "Your Strava account has been disconnected.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to disconnect Strava.",
        variant: "destructive",
      });
    },
  });

  const syncStravaMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/v1/strava/sync");
      return response.json();
    },
    onSuccess: (data: { imported: number; skipped: number; total: number }) => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/strava/status"] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/timeline"] });
      queryClient.invalidateQueries({ queryKey: ["/api/v1/workouts"] });
      toast({
        title: "Sync Complete",
        description: `Imported ${data.imported} new activities. ${data.skipped} already existed.`,
      });
    },
    onError: () => {
      toast({
        title: "Sync Failed",
        description: "Failed to sync activities from Strava.",
        variant: "destructive",
      });
    },
  });

  return {
    connectStravaMutation,
    disconnectStravaMutation,
    syncStravaMutation,
  };
}

