import { Button } from "@/components/ui/button";
import { useEffect, useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Loader2 } from "lucide-react";
import { useLocation, useSearch } from "wouter";
import { ProfileSection } from "@/components/settings/ProfileSection";
import { StravaSection } from "@/components/settings/StravaSection";
import { PreferencesSection } from "@/components/settings/PreferencesSection";
import { DataToolsSection } from "@/components/settings/DataToolsSection";
import { CoachingSection } from "@/components/settings/CoachingSection";

interface Preferences {
  weightUnit: string;
  distanceUnit: string;
  weeklyGoal: number;
  emailNotifications: boolean;
  aiCoachEnabled: boolean;
}

interface StravaStatus {
  connected: boolean;
  athleteId?: string;
  lastSyncedAt?: string | null;
}

export default function Settings() {
  const { toast } = useToast();
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const search = useSearch();
  const [weightUnit, setWeightUnit] = useState("kg");
  const [distanceUnit, setDistanceUnit] = useState("km");
  const [weeklyGoal, setWeeklyGoal] = useState("5");
  const [emailNotifications, setEmailNotifications] = useState(true);
  const [aiCoachEnabled, setAiCoachEnabled] = useState(true);
  const [hasChanges, setHasChanges] = useState(false);

  useEffect(() => {
    const params = new URLSearchParams(search);
    const stravaStatus = params.get("strava");
    if (stravaStatus === "connected") {
      toast({
        title: "Strava Connected",
        description: "Your Strava account has been successfully connected.",
      });
      setLocation("/settings", { replace: true });
    } else if (stravaStatus === "error") {
      toast({
        title: "Connection Failed",
        description: "Failed to connect to Strava. Please try again.",
        variant: "destructive",
      });
      setLocation("/settings", { replace: true });
    }
  }, [search, toast, setLocation]);

  const { data: preferences, isLoading } = useQuery<Preferences>({
    queryKey: ["/api/v1/preferences"],
  });

  const { data: stravaStatus, isLoading: stravaLoading } =
    useQuery<StravaStatus>({
      queryKey: ["/api/v1/strava/status"],
    });

  useEffect(() => {
    if (preferences) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setWeightUnit(preferences.weightUnit || "kg");
      setDistanceUnit(preferences.distanceUnit || "km");
      setWeeklyGoal(String(preferences.weeklyGoal || 5));
      setEmailNotifications(preferences.emailNotifications);
      setAiCoachEnabled(preferences.aiCoachEnabled ?? true);
    }
  }, [preferences]);

  const saveMutation = useMutation({
    mutationFn: async (data: {
      weightUnit: string;
      distanceUnit: string;
      weeklyGoal: number;
      emailNotifications: boolean;
      aiCoachEnabled: boolean;
    }) => {
      const response = await apiRequest("PATCH", "/api/v1/preferences", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/v1/preferences"] });
      setHasChanges(false);
      toast({
        title: "Settings saved",
        description: "Your preferences have been updated.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to save settings. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleSave = () => {
    saveMutation.mutate({
      weightUnit,
      distanceUnit,
      weeklyGoal: Number.parseInt(weeklyGoal, 10),
      emailNotifications,
      aiCoachEnabled,
    });
  };

  const markChanged = () => setHasChanges(true);

  let userName = "User";
  if (user) {
    if (user.firstName && user.lastName) {
      userName = `${user.firstName} ${user.lastName}`;
    } else if (user.email) {
      userName = user.email;
    }
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 max-w-2xl mx-auto space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Settings</h1>
        <p className="text-muted-foreground mt-1">
          Manage your account and preferences
        </p>
      </div>

      <ProfileSection userName={userName} />

      <StravaSection
        stravaStatus={stravaStatus}
        stravaLoading={stravaLoading}
      />

      <PreferencesSection
        weightUnit={weightUnit}
        distanceUnit={distanceUnit}
        weeklyGoal={weeklyGoal}
        emailNotifications={emailNotifications}
        aiCoachEnabled={aiCoachEnabled}
        onWeightUnitChange={(v) => {
          setWeightUnit(v);
          markChanged();
        }}
        onDistanceUnitChange={(v) => {
          setDistanceUnit(v);
          markChanged();
        }}
        onWeeklyGoalChange={(v) => {
          setWeeklyGoal(v);
          markChanged();
        }}
        onEmailNotificationsChange={(v) => {
          setEmailNotifications(v);
          markChanged();
        }}
        onAiCoachEnabledChange={(v) => {
          setAiCoachEnabled(v);
          markChanged();
        }}
      />

      <CoachingSection />

      <DataToolsSection />

      <Button
        onClick={handleSave}
        className="w-full"
        data-testid="button-save-settings"
        disabled={!hasChanges || saveMutation.isPending}
      >
        {saveMutation.isPending ? (
          <>
            <Loader2 className="h-4 w-4 animate-spin mr-2" />
            Saving...
          </>
        ) : (
          "Save Settings"
        )}
      </Button>
    </div>
  );
}

import { env } from "./env";
import { logger } from "./logger";
import { clerkMiddleware, getAuth, clerkClient } from "@clerk/express";
import type { Express, RequestHandler } from "express";
import { storage } from "./storage";

export const DEV_USER_ID = "dev-user";

function isDev(): boolean {
  return env.NODE_ENV === "development";
}

function isDevBypassEnabled(): boolean {
  return isDev() && env.ALLOW_DEV_AUTH_BYPASS === "true";
}

function hasClerkKeys(): boolean {
  return !!(env.CLERK_PUBLISHABLE_KEY && env.CLERK_SECRET_KEY);
}

async function ensureDevUserExists(): Promise<void> {
  const existing = await storage.getUser(DEV_USER_ID);
  if (existing) return;
  await storage.upsertUser({
    id: DEV_USER_ID,
    email: "dev@localhost",
    firstName: "Dev",
    lastName: "User",
    profileImageUrl: null,
  });
}

export async function setupAuth(app: Express) {
  app.set("trust proxy", 1);

  if (hasClerkKeys()) {
    app.use(clerkMiddleware());
  } else if (isDevBypassEnabled()) {
    logger.info("[DEV] No Clerk keys found — using dev auth bypass");
    await ensureDevUserExists();
  } else {
    throw new Error(
      "Missing Clerk environment variables. Please set CLERK_PUBLISHABLE_KEY and CLERK_SECRET_KEY.",
    );
  }

  if (isDevBypassEnabled()) {
    await ensureDevUserExists();
    logger.info("[DEV] Dev auth fallback enabled for iframe/preview contexts");
  }
}

export const isAuthenticated: RequestHandler = async (req, res, next) => {
  if (hasClerkKeys()) {
    const auth = getAuth(req);
    if (auth?.userId) {
      try {
        await ensureUserExists(auth.userId);
      } catch (error) {
        logger.error({ err: error }, "Error syncing user:");
        return res.status(500).json({ error: "Failed to initialize user session" });
      }
      return next();
    }
  }

  if (isDevBypassEnabled()) {
    try {
      await ensureDevUserExists();
    } catch (error) {
      logger.error({ err: error }, "Error creating dev user:");
      return res.status(500).json({ error: "Failed to initialize dev user session" });
    }
    return next();
  }

  return res.status(401).json({ error: "Unauthorized" });
};

async function ensureUserExists(clerkUserId: string): Promise<void> {
  const existing = await storage.getUser(clerkUserId);
  if (existing) return;

  const clerkUser = await clerkClient.users.getUser(clerkUserId);
  const email = clerkUser.emailAddresses?.[0]?.emailAddress || null;

  await storage.upsertUser({
    id: clerkUserId,
    email,
    firstName: clerkUser.firstName,
    lastName: clerkUser.lastName,
    profileImageUrl: clerkUser.imageUrl,
  });
}

import { env } from "./env";
import * as Sentry from "@sentry/node";
import express, { type Request, Response, NextFunction } from "express";
import compression from "compression";
import helmet from "helmet";
import { logger } from "./logger";
import pinoHttp from "pino-http";
import { registerRoutes } from "./routes";
import { serveStatic } from "./static";
import swaggerUi from "swagger-ui-express";
import { generateOpenApiDocument } from "../shared/openapi";

import { createServer } from "node:http";
import { randomUUID } from "node:crypto";
import { storage } from "./storage";
import { pool } from "./db";
import { getAuth } from "@clerk/express";
import { runStartupMaintenance } from "./maintenance";

if (env.SENTRY_DSN) {
  Sentry.init({
    dsn: env.SENTRY_DSN,
    environment: env.NODE_ENV || "development",
    sendDefaultPii: true,
  });
}

const app = express();
const httpServer = createServer(app);

export interface AppError extends Error {
  status?: number;
  statusCode?: number;
}

declare module "http" {
  interface IncomingMessage {
    rawBody: unknown;
  }
}

app.use(compression());

const isDev = env.NODE_ENV !== "production";
const clerkDomains =
  "https://*.clerk.accounts.dev https://*.hyroxcompanion.life https://clerk.hyroxcompanion.life";
const connectSrc = isDev
  ? [
      "'self'",
      clerkDomains,
      "https://www.strava.com",
      "https://*.ingest.us.sentry.io",
      "ws:",
      "wss:",
    ]
  : [
      "'self'",
      clerkDomains,
      "https://www.strava.com",
      "https://*.ingest.us.sentry.io",
    ];
const scriptSrc = isDev
  ? ["'self'", "'unsafe-inline'", "'unsafe-eval'", clerkDomains]
  : ["'self'", "'unsafe-inline'", clerkDomains];

app.use(
  helmet({
    contentSecurityPolicy: {
      directives: {
        defaultSrc: ["'self'"],
        scriptSrc,
        styleSrc: [
          "'self'",
          "'unsafe-inline'",
          "https://fonts.googleapis.com",
          clerkDomains,
        ],
        fontSrc: ["'self'", "https://fonts.gstatic.com"],
        imgSrc: ["'self'", "data:", "https:"],
        connectSrc,
        frameSrc: ["'self'", clerkDomains],
        workerSrc: ["'self'", "blob:"],
      },
    },
    crossOriginEmbedderPolicy: false,
    referrerPolicy: { policy: "strict-origin-when-cross-origin" },
  }),
);

app.use((req, res, next) => {
  res.setHeader(
    "Permissions-Policy",
    "camera=(), microphone=(self), geolocation=()",
  );
  next();
});

app.use(
  express.json({
    limit: "5mb", // 🛡️ Sentinel: Limit request body size to prevent DoS
    verify: (req, _res, buf) => {
      req.rawBody = buf;
    },
  }),
);

app.use(express.urlencoded({ extended: false }));

app.get("/api/v1/health", (_req, res) => {
  res.json({ status: "ok", timestamp: Date.now() });
});



app.use(pinoHttp({
  logger,
  genReqId: (req) => req.headers['x-request-id'] || randomUUID(),
  customProps: (req, _res) => {
    let userId = 'anonymous';
    try {
      const auth = getAuth(req as Request);
      if (auth?.userId) {
        userId = auth.userId;
      }
    } catch {
      userId = 'anonymous';
    }

    return {
      context: 'http',
      userId,
      requestId: req.id,
      route: req.url || req.originalUrl,
    };
  },
  autoLogging: {
    ignore: (req) => !req.url?.startsWith('/api/v1')
  }
}));

await runStartupMaintenance(storage);
await registerRoutes(httpServer, app);

// Serve OpenAPI docs
app.use(
  "/api/docs",
  swaggerUi.serve,
  swaggerUi.setup(generateOpenApiDocument(), {
    customCss: ".swagger-ui .topbar { display: none } .swagger-ui .info { margin: 20px 0; }",
    customSiteTitle: "Workout API Documentation"
  })
);


app.use((err: AppError, _req: Request, res: Response, _next: NextFunction) => {
  const status = err.status || err.statusCode || 500;
  // 🛡️ Sentinel: Prevent leaking sensitive error details to the client
  const message =
    status === 500
      ? "Internal Server Error"
      : err.message || "An error occurred";

  Sentry.captureException(err);
  res.status(status).json({ error: message });
});

// importantly only setup vite in development and after
// setting up all the other routes so the catch-all route
// doesn't interfere with the other routes
if (env.NODE_ENV === "production") {
  serveStatic(app);
} else {
  const { setupVite } = await import("./vite");
  await setupVite(httpServer, app);
}

// ALWAYS serve the app on the port specified in the environment variable PORT
// Other ports are firewalled. Default to 5000 if not specified.
// this serves both the API and the client.
// It is the only port that is not firewalled.
const port = Number.parseInt(env.PORT || "5000", 10);

httpServer.listen(
  {
    port,
    host: "0.0.0.0",
    reusePort: true,
  },
  () => {
    logger.info({ port }, `serving on port ${port}`);
  },
);

// Graceful shutdown
const shutdown = () => {
  logger.info("Received shutdown signal. Closing HTTP server...");
  httpServer.close(() => {
    logger.info("HTTP server closed. Draining database pool...");
    pool.end().then(() => {
      logger.info("Database pool drained. Exiting process.");
      process.exit(0);
    });
  });
};

process.on("SIGTERM", shutdown);
process.on("SIGINT", shutdown);

import { logger } from "../logger";
