router.post("/api/v1/timeline/ai-suggestions", isAuthenticated, rateLimiter("suggestions", 3), async (req: ExpressRequest, res: Response) => {
  try {
    const userId = getUserId(req);

    const [trainingContext, coachingMaterialsList] = await Promise.all([
      buildTrainingContext(userId),
      storage.listCoachingMaterials(userId),
    ]);

    const coachingMaterials = buildCoachingMaterialsSection(coachingMaterialsList) || undefined;
    const timeline = await storage.getTimeline(userId);
    const today = toDateStr();

    const upcomingWorkouts: UpcomingWorkout[] = timeline
      .filter(entry =>
        entry.status === "planned" &&
        entry.date &&
        entry.date >= today &&
        entry.planDayId !== null
      )
      // Fast string comparison for YYYY-MM-DD dates instead of localeCompare
      .sort((a, b) => {
        if (b.date < a.date) return 1;
        if (b.date > a.date) return -1;
        return 0;
      })
      .slice(0, 5)
      .map(entry => ({
        id: entry.planDayId || "",
        date: entry.date,
        focus: entry.focus || "",
        mainWorkout: entry.mainWorkout || "",
        accessory: entry.accessory || undefined,
        notes: entry.notes || undefined,
      }));

    if (upcomingWorkouts.length === 0) {
      return res.json({ suggestions: [], message: "No upcoming planned workouts found" });
    }

    const rawSuggestions = await generateWorkoutSuggestions(trainingContext, upcomingWorkouts, undefined, coachingMaterials);

    const workoutMap = new Map(upcomingWorkouts.map(w => [w.id, w]));
    const suggestions = rawSuggestions
      .map(s => {
        const workout = workoutMap.get(s.workoutId);
        return {
          workoutId: s.workoutId,
          date: workout?.date || s.workoutDate || "",
          focus: workout?.focus || s.workoutFocus || "",
          targetField: s.targetField || "notes",
          action: s.action || "append",
          recommendation: s.recommendation,
          rationale: s.rationale,
          priority: s.priority,
        };
      })
      .filter(s => s.date && s.focus && s.recommendation);

    res.json({ suggestions });
  } catch (error) {
    (req.log || logger).error({ err: error }, "AI suggestions error:");
    res.status(500).json({ error: "Failed to generate AI suggestions" });
  }
});

export default router;

import { logger } from "../logger";
import { Router, type Request as ExpressRequest, type Response } from "express";
import { isAuthenticated } from "../clerkAuth";
import { storage } from "../storage";
import { calculatePersonalRecords, calculateExerciseAnalytics, type ExerciseSetWithDate } from "../services/analyticsService";
import { getUserId } from "../types";
import { rateLimiter } from "../routeUtils";
import { dateStringSchema } from "@shared/schema";

const router = Router();

// Cache TTL in milliseconds (5 minutes)
const CACHE_TTL_MS = 5 * 60 * 1000;

interface CacheEntry {
  promise: Promise<ExerciseSetWithDate[]>;
  timestamp: number;
}

// Store pending promises and cached results to prevent redundant DB queries
// for both concurrent and sequential requests within the TTL window.
export const _cacheForTesting = new Map<string, CacheEntry>();
const cache = _cacheForTesting;

function getExerciseSetsCoalesced(userId: string, from?: string, to?: string): Promise<ExerciseSetWithDate[]> {
  const cacheKey = `${userId}-${from || 'none'}-${to || 'none'}`;
  const now = Date.now();

  const entry = cache.get(cacheKey);
  if (entry && (now - entry.timestamp < CACHE_TTL_MS)) {
    return entry.promise;
  }

  // If expired or missing, fetch from storage
  const promise = storage.getAllExerciseSetsWithDates(userId, from, to)
    .catch((error) => {
      // Remove from cache on failure so subsequent requests retry immediately
      cache.delete(cacheKey);
      throw error;
    });

  cache.set(cacheKey, { promise, timestamp: now });
  return promise;
}

export function validDate(val: unknown): string | undefined {
  if (!val) return undefined;
  const parsed = dateStringSchema.safeParse(val);
  return parsed.success ? parsed.data : undefined;
}

router.get("/api/v1/personal-records", isAuthenticated, rateLimiter("analytics", 20), async (req: ExpressRequest<{}, any, any, { from?: string; to?: string }>, res: Response) => {
  try {
    const userId = getUserId(req);
    const from = validDate(req.query.from);
    const to = validDate(req.query.to);

    if (req.query.from && !from) return res.status(400).json({ error: "Invalid 'from' date format" });
    if (req.query.to && !to) return res.status(400).json({ error: "Invalid 'to' date format" });
    const allSets = await getExerciseSetsCoalesced(userId, from, to);
    res.json(calculatePersonalRecords(allSets));
  } catch (error) {
    (req.log || logger).error({ err: error }, "Error fetching PRs:");
    res.status(500).json({ error: "Failed to fetch personal records" });
  }
});

router.get("/api/v1/exercise-analytics", isAuthenticated, rateLimiter("analytics", 20), async (req: ExpressRequest<{}, any, any, { from?: string; to?: string }>, res: Response) => {
  try {
    const userId = getUserId(req);
    const from = validDate(req.query.from);
    const to = validDate(req.query.to);

    if (req.query.from && !from) return res.status(400).json({ error: "Invalid 'from' date format" });
    if (req.query.to && !to) return res.status(400).json({ error: "Invalid 'to' date format" });

    const allSets = await getExerciseSetsCoalesced(userId, from, to);
    res.json(calculateExerciseAnalytics(allSets));
  } catch (error) {
    (req.log || logger).error({ err: error }, "Error fetching exercise analytics:");
    res.status(500).json({ error: "Failed to fetch exercise analytics" });
  }
});

